import { FeatureContext, FeatureHandle } from "../application/featureContext";
import { norm } from "../lib/utils";

type Severity = "warn" | "error";

export interface CompatibilityIssue {
  id: string;
  severity: Severity;
  title: string;
  details?: string;
}

const TOAST_ROOT_ID = "qqrm-compat-toast-root";
const TOAST_ID = "qqrm-compat-toast";

function isChatUiLike(): boolean {
  // Avoid noisy warnings on non-chat pages (login / marketing / blank pages).
  if (document.getElementById("prompt-textarea")) return true;
  if (document.querySelector("form.group\\/composer")) return true;
  if (document.querySelector('[data-testid="composer-footer-actions"]')) return true;
  if (document.querySelector('nav[aria-label="Chat history"]')) return true;
  if (document.getElementById("history")) return true;
  return false;
}

function findComposerRoot(): HTMLElement | null {
  const byClass = document.querySelector<HTMLElement>("form.group\\/composer");
  if (byClass) return byClass;
  const byFooter = document.querySelector<HTMLElement>('[data-testid="composer-footer-actions"]');
  if (byFooter) return byFooter.closest("form") as HTMLElement | null;
  const prompt = document.getElementById("prompt-textarea") as HTMLElement | null;
  if (prompt) return prompt.closest("form, footer") as HTMLElement | null;
  return null;
}

function findComposerInput(root?: HTMLElement | null): HTMLElement | HTMLTextAreaElement | null {
  const scope = root ?? document;
  const textarea = scope.querySelector("textarea") as HTMLTextAreaElement | null;
  if (textarea) return textarea;
  const ce = scope.querySelector('[contenteditable="true"]') as HTMLElement | null;
  if (ce) return ce;
  const byId = document.getElementById("prompt-textarea") as HTMLElement | null;
  if (byId) return byId;
  return null;
}

function findSendButton(root?: HTMLElement | null): HTMLButtonElement | null {
  const scope = root ?? document;
  const byTestId = scope.querySelector<HTMLButtonElement>('[data-testid="send-button"]');
  if (byTestId) return byTestId;
  const submit = scope.querySelector<HTMLButtonElement>('button[type="submit"]');
  if (submit) return submit;
  const any = scope.querySelector<HTMLButtonElement>('button[aria-label*="send" i]');
  return any;
}

function hasDictationToggle(): boolean {
  return Boolean(
    document.querySelector('button[data-testid="composer-speech-button"]') ??
    document.querySelector('button[aria-label="Dictate button"]') ??
    document.querySelector('button[aria-label*="dictate" i]')
  );
}

function hasTemporaryChatToggle(): boolean {
  return Boolean(
    document.querySelector('button[aria-label*="temporary chat" i]') ??
    document.querySelector('[data-testid*="temporary" i]')
  );
}

function hasHistoryOptionsButtons(): boolean {
  return Boolean(
    document.querySelector('button[data-testid^="history-item-"][data-testid$="-options"]') ??
    document.querySelector('button[aria-label*="conversation options" i]') ??
    document.querySelector('button[aria-label*="open conversation options" i]')
  );
}

function hasHistoryRoot(): boolean {
  return Boolean(document.getElementById("history"));
}

function hasYourChatsExpandoToggle(): boolean {
  return Boolean(
    document.querySelector("div.group\\/sidebar-expando-section button[aria-expanded]") ??
    document.querySelector('button[aria-expanded][aria-controls*="history" i]')
  );
}

function hasOpenSidebarButton(): boolean {
  return Boolean(
    document.querySelector(
      'button[aria-label="Open sidebar"][aria-controls="stage-slideover-sidebar"]'
    ) ?? document.querySelector('button[aria-label="Open sidebar"]')
  );
}

function hasUserMessages(): boolean {
  return Boolean(document.querySelector('[data-message-author-role="user"]'));
}

function hasEditButtons(): boolean {
  const btns = Array.from(document.querySelectorAll<HTMLElement>("button"));
  for (const b of btns) {
    const dt = norm(b.getAttribute("data-testid"));
    const a = norm(b.getAttribute("aria-label"));
    const t = norm(b.getAttribute("title"));
    const txt = norm(b.textContent);
    if (dt.includes("edit")) return true;
    if (a.includes("edit") || a.includes("редакт") || a.includes("измен")) return true;
    if (t.includes("edit") || t.includes("редакт") || t.includes("измен")) return true;
    if (txt.includes("edit") || txt.includes("редакт") || txt.includes("измен")) return true;
  }
  return false;
}

export function runCompatibilityChecks(ctx: FeatureContext): CompatibilityIssue[] {
  if (!ctx.settings.showCompatibilityWarnings) return [];
  if (!isChatUiLike()) return [];

  const issues: CompatibilityIssue[] = [];

  const composerRoot = findComposerRoot();
  const composerInput = findComposerInput(composerRoot);
  const sendBtn = findSendButton(composerRoot);

  const needsComposer = ctx.settings.autoSend || ctx.settings.ctrlEnterSends;
  if (needsComposer) {
    if (!composerRoot) {
      issues.push({
        id: "composer.root",
        severity: "error",
        title: "Composer not found",
        details: "The message composer container could not be located."
      });
    } else {
      if (!composerInput) {
        const hasCanvas = Boolean(composerRoot.querySelector("canvas"));
        issues.push({
          id: "composer.input",
          severity: "error",
          title: "Composer input not found",
          details: hasCanvas
            ? "Only a canvas-based input was detected. The extension expects textarea/contenteditable."
            : "No textarea/contenteditable input found inside the composer."
        });
      }
      if (!sendBtn) {
        issues.push({
          id: "composer.send",
          severity: "warn",
          title: "Send button not found",
          details: "Auto-send / Ctrl+Enter may fail because the Send button selector did not match."
        });
      }
    }
  }

  if (ctx.settings.startDictation && !hasDictationToggle()) {
    issues.push({
      id: "dictation.toggle",
      severity: "warn",
      title: "Dictation toggle not found",
      details: "Ctrl+Space dictation toggle may be outdated for the current ChatGPT UI."
    });
  }

  if (ctx.settings.autoTempChat && !hasTemporaryChatToggle()) {
    issues.push({
      id: "tempchat.toggle",
      severity: "warn",
      title: "Temporary Chat toggle not found",
      details: "Auto-enable Temporary Chat may no longer match the current ChatGPT UI."
    });
  }

  if (ctx.settings.oneClickDelete && !hasHistoryOptionsButtons()) {
    issues.push({
      id: "history.options",
      severity: "warn",
      title: "Chat history menu buttons not found",
      details: "One-click delete / rename (F2) depend on chat history options buttons."
    });
  }

  if (ctx.settings.autoExpandChats) {
    if (!hasHistoryRoot()) {
      issues.push({
        id: "sidebar.history",
        severity: "warn",
        title: "Sidebar history container not found",
        details:
          "Auto-expand chats expects a #history container (or equivalent) in the left sidebar."
      });
    }

    if (!hasYourChatsExpandoToggle()) {
      issues.push({
        id: "sidebar.expando",
        severity: "warn",
        title: "Sidebar expando toggle not detected",
        details:
          'Auto-expand chats relies on an expando header with aria-expanded (e.g. "Your chats").'
      });
    }

    // Not always required (sidebar can be permanently open), but useful to detect UI changes.
    if (!hasOpenSidebarButton() && !document.querySelector("#stage-slideover-sidebar")) {
      issues.push({
        id: "sidebar.openBtn",
        severity: "warn",
        title: "Open sidebar button not found",
        details:
          'If the sidebar is collapsed by default, auto-expand may fail without an "Open sidebar" button.'
      });
    }
  }

  if (ctx.settings.editLastMessageOnArrowUp) {
    if (!hasUserMessages()) {
      issues.push({
        id: "editlast.messages",
        severity: "warn",
        title: "No user messages found",
        details: "ArrowUp edit needs at least one user message in the conversation view."
      });
    } else if (!hasEditButtons()) {
      issues.push({
        id: "editlast.buttons",
        severity: "warn",
        title: "Edit controls not detected",
        details: "The extension could not detect any edit controls for user messages."
      });
    }
  }

  if (ctx.settings.wideChatWidth > 0) {
    const main = document.querySelector("main");
    if (!main) {
      issues.push({
        id: "widechat.main",
        severity: "warn",
        title: "Main container not found",
        details: "Wide Chat could not find <main>, so the width override may not apply."
      });
    }
  }

  return issues;
}

function ensureToastRoot(): HTMLElement {
  let root = document.getElementById(TOAST_ROOT_ID) as HTMLElement | null;
  if (root) return root;
  root = document.createElement("div");
  root.id = TOAST_ROOT_ID;
  root.style.position = "fixed";
  root.style.right = "14px";
  root.style.bottom = "14px";
  root.style.zIndex = "2147483647";
  root.style.pointerEvents = "none";
  document.documentElement.appendChild(root);
  return root;
}

function removeToast() {
  const toast = document.getElementById(TOAST_ID);
  toast?.remove();
}

function showToast(issues: CompatibilityIssue[]) {
  removeToast();
  const root = ensureToastRoot();

  const toast = document.createElement("div");
  toast.id = TOAST_ID;
  toast.style.pointerEvents = "auto";
  toast.style.maxWidth = "340px";
  toast.style.borderRadius = "12px";
  toast.style.border = "1px solid rgba(255,255,255,0.14)";
  toast.style.background = "rgba(20, 22, 26, 0.86)";
  toast.style.color = "#fff";
  toast.style.padding = "10px 10px 8px";
  toast.style.font = "12px/16px system-ui, -apple-system, Segoe UI, Roboto, Arial";
  toast.style.boxShadow = "0 10px 30px rgba(0,0,0,0.35)";
  toast.style.backdropFilter = "blur(8px)";

  const header = document.createElement("div");
  header.style.display = "flex";
  header.style.alignItems = "center";
  header.style.justifyContent = "space-between";
  header.style.gap = "8px";

  const title = document.createElement("div");
  title.textContent = "Compatibility check";
  title.style.fontWeight = "600";

  const close = document.createElement("button");
  close.type = "button";
  close.textContent = "×";
  close.style.border = "none";
  close.style.background = "transparent";
  close.style.color = "rgba(255,255,255,0.8)";
  close.style.fontSize = "16px";
  close.style.lineHeight = "16px";
  close.style.cursor = "pointer";
  close.addEventListener("click", () => removeToast());

  header.appendChild(title);
  header.appendChild(close);
  toast.appendChild(header);

  const list = document.createElement("ul");
  list.style.margin = "8px 0 0";
  list.style.padding = "0 0 0 18px";

  for (const issue of issues.slice(0, 6)) {
    const item = document.createElement("li");
    item.textContent = issue.title;
    item.style.margin = "2px 0";
    list.appendChild(item);
  }
  toast.appendChild(list);

  if (issues.length > 6) {
    const more = document.createElement("div");
    more.textContent = `…and ${issues.length - 6} more`;
    more.style.marginTop = "4px";
    more.style.color = "rgba(255,255,255,0.7)";
    toast.appendChild(more);
  }

  root.appendChild(toast);

  // Auto-hide after a while, but keep it long enough to notice.
  window.setTimeout(() => {
    if (document.getElementById(TOAST_ID)) removeToast();
  }, 12000);
}

export function initCompatibilityMonitorFeature(ctx: FeatureContext): FeatureHandle {
  let enabled = Boolean(ctx.settings.showCompatibilityWarnings);
  let lastIds = new Set<string>();
  let scheduled = false;
  let mo: MutationObserver | null = null;

  const logIssues = (issues: CompatibilityIssue[]) => {
    for (const issue of issues) {
      const prefix = "[cgptbe][compat]";
      const msg = `${prefix} ${issue.title}`;
      if (issue.severity === "error") console.error(msg, issue.details ?? "");
      else console.warn(msg, issue.details ?? "");
    }
  };

  const evaluate = () => {
    if (!enabled) return;
    const issues = runCompatibilityChecks(ctx);
    const currentIds = new Set(issues.map((x) => x.id));

    const hasNew = issues.some((x) => !lastIds.has(x.id));
    lastIds = currentIds;

    if (issues.length === 0) {
      removeToast();
      return;
    }

    if (hasNew) {
      logIssues(issues);
      showToast(issues);
    }
  };

  const schedule = () => {
    if (!enabled) return;
    if (scheduled) return;
    scheduled = true;
    window.setTimeout(() => {
      scheduled = false;
      evaluate();
    }, 800);
  };

  const start = () => {
    if (mo) return;
    schedule();
    mo = new MutationObserver(() => schedule());
    mo.observe(document.documentElement, { childList: true, subtree: true });
    window.setTimeout(() => evaluate(), 2000);
  };

  const stop = () => {
    mo?.disconnect();
    mo = null;
    lastIds = new Set();
    removeToast();
  };

  if (enabled) start();

  return {
    name: "compatibilityMonitor",
    dispose: () => stop(),
    onSettingsChange: (next) => {
      const nextEnabled = Boolean(next.showCompatibilityWarnings);
      if (nextEnabled === enabled) return;
      enabled = nextEnabled;
      if (enabled) start();
      else stop();
    },
    getStatus: () => ({ active: enabled })
  };
}
